UPDATE ${prefix}EXPORTER_POSITION
SET LAST_EXPORTED_POSITION = #{lastExportedPosition}, LAST_UPDATED = #{lastUpdated}
WHERE PARTITION_ID = #{partitionId}

mapper.select:
SELECT
  COALESCE(MIN(pg_wal_lsn_diff(replay_lsn, '0/0')), 0)::bigint AS min_replication_lsn
FROM pg_stat_replication;

SELECT DURABLE_LSN AS last_lsn
FROM aurora_global_db_instance_status()
WHERE SESSION_ID = 'MASTER_SESSION_ID';
